#!/usr/bin/perl -w   # The shebang line, it's necessary to declare that we are going in binary mode or else 'cat'-ing may not work correctly 
use strict;         use CGI qw(:standard);                     # Import perl module for handling http request.   
my $comment = param('comment');                           # Get the comment from GET parameters, as defined by web server (e.g., Apache).  
print header(-type=>'text/html', -charset => 'utf-8'),  "<div>$comment<\/div>";             print"\n";